// And groups predicates with the AND operator between them.
func And(predicates ...predicate.Cita) predicate.Cita {
	return predicate.Cita(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.Cita) predicate.Cita {
	return predicate.Cita(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.Cita) predicate.Cita {
	return predicate.Cita(sql.NotPredicates(p))
}
